import React, { useState } from "react";
import axios from "axios";

function App() {
  const [matricula, setMatricula] = useState("");
  const [senha, setSenha] = useState("");
  const [loggedIn, setLoggedIn] = useState(false);
  const [formData, setFormData] = useState({
    data_atividade: "",
    supervisor: "",
    status: "",
    eletricista_motorista: "",
    eletricista_parceiro: "",
    equipe: "",
    servico: "",
    placa_veiculo: "",
  });
  const [teams, setTeams] = useState([]);

  const handleLogin = async () => {
    try {
      const response = await axios.post("http://localhost:5000/login", { matricula, senha });
      if (response.data.message === "Login bem-sucedido") {
        setLoggedIn(true);
        alert("Login bem-sucedido!");
      }
    } catch (error) {
      alert("Erro ao fazer login");
    }
  };

  const fetchTeams = async () => {
    try {
      const response = await axios.get("http://localhost:5000/teams", {
        params: {
          data: formData.data_atividade,
        },
      });
      setTeams(response.data);
    } catch (error) {
      console.error("Erro ao buscar equipes:", error);
    }
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post("http://localhost:5000/teams", formData);
      setFormData({
        data_atividade: "",
        supervisor: "",
        status: "",
        eletricista_motorista: "",
        eletricista_parceiro: "",
        equipe: "",
        servico: "",
        placa_veiculo: "",
      });
      fetchTeams(); // Atualiza a lista de equipes
    } catch (error) {
      alert("Erro ao cadastrar equipe");
    }
  };

  if (!loggedIn) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-100">
        <div className="bg-white p-8 rounded-lg shadow-lg w-96">
          <h1 className="text-2xl font-bold text-center mb-6">Login</h1>
          <div className="space-y-4">
            <input
              type="text"
              placeholder="Matrícula"
              value={matricula}
              onChange={(e) => setMatricula(e.target.value)}
              className="w-full p-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
            <input
              type="password"
              placeholder="Senha"
              value={senha}
              onChange={(e) => setSenha(e.target.value)}
              className="w-full p-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
            <button
              onClick={handleLogin}
              className="w-full bg-blue-600 text-white p-2 rounded-md hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              Entrar
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 max-w-6xl mx-auto bg-white shadow-lg rounded-lg mt-10">
      <h1 className="text-3xl font-semibold text-gray-700 text-center mb-6">
        Cadastro de Equipes
      </h1>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="grid grid-cols-2 gap-4">
          <input
            type="date"
            name="data_atividade"
            value={formData.data_atividade}
            onChange={handleChange}
            required
            className="w-full p-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
          <input
            type="text"
            name="supervisor"
            value={formData.supervisor}
            onChange={handleChange}
            placeholder="Supervisor"
            required
            className="w-full p-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
        </div>
        <div className="grid grid-cols-2 gap-4">
          <input
            type="text"
            name="status"
            value={formData.status}
            onChange={handleChange}
            placeholder="Status"
            required
            className="w-full p-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
          <input
            type="text"
            name="equipe"
            value={formData.equipe}
            onChange={handleChange}
            placeholder="Equipe"
            required
            className="w-full p-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
        </div>
        <div className="grid grid-cols-2 gap-4">
          <input
            type="text"
            name="eletricista_motorista"
            value={formData.eletricista_motorista}
            onChange={handleChange}
            placeholder="Eletricista Motorista"
            required
            className="w-full p-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
          <input
            type="text"
            name="eletricista_parceiro"
            value={formData.eletricista_parceiro}
            onChange={handleChange}
            placeholder="Eletricista Parceiro"
            required
            className="w-full p-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
        </div>
        <div className="grid grid-cols-2 gap-4">
          <input
            type="text"
            name="servico"
            value={formData.servico}
            onChange={handleChange}
            placeholder="Serviço"
            required
            className="w-full p-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
          <input
            type="text"
            name="placa_veiculo"
            value={formData.placa_veiculo}
            onChange={handleChange}
            placeholder="Placa do Veículo"
            required
            className="w-full p-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
        </div>
        <button
          type="submit"
          className="w-full bg-blue-600 text-white p-2 rounded-md hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
        >
          Cadastrar
        </button>
      </form>

      <button
        onClick={fetchTeams}
        className="mt-4 w-full bg-purple-600 text-white p-2 rounded-md hover:bg-purple-700 focus:outline-none focus:ring-2 focus:ring-purple-500"
      >
        Buscar Equipes
      </button>

      <h2 className="text-xl font-semibold text-gray-700 mt-6">Equipes Cadastradas</h2>
      <div className="overflow-x-auto mt-3">
        <table className="min-w-full bg-white border rounded-lg">
          <thead>
            <tr className="bg-gray-200 text-gray-700 text-sm">
              <th className="p-2 border">Data</th>
              <th className="p-2 border">Supervisor</th>
              <th className="p-2 border">Status</th>
              <th className="p-2 border">Equipe</th>
              <th className="p-2 border">Eletricista Motorista</th>
              <th className="p-2 border">Eletricista Parceiro</th>
              <th className="p-2 border">Serviço</th>
              <th className="p-2 border">Placa</th>
            </tr>
          </thead>
          <tbody className="text-sm">
            {teams.map((team) => (
              <tr key={team.id} className="text-center">
                <td className="p-2 border">{team.data_atividade}</td>
                <td className="p-2 border">{team.supervisor}</td>
                <td className="p-2 border">{team.status}</td>
                <td className="p-2 border">{team.equipe}</td>
                <td className="p-2 border">{team.eletricista_motorista}</td>
                <td className="p-2 border">{team.eletricista_parceiro}</td>
                <td className="p-2 border">{team.servico}</td>
                <td className="p-2 border">{team.placa_veiculo}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default App;
